        "y_axis_left": {
          "label": "{argument name=\"left axis label\" default=\"Violent Crime Rate Par 100-000\"}",
          "scale": ["200", "400", "500", "600", "700", "800", "800", "1000"],
          "color": "black"
        },
        "y_axis_right": {
          "label": "{argument name=\"right axis label\" default=\"% Of Americans Saying Crime Is 'Up'\"}",
